function executar(acao) {
  acao();
}

executar(function () {
  console.log("Executado pelo contexto principal.");
});

function paraCadaItem(lista, acao) {
  for (let i = 0; i < lista.length; i = i + 1) {
    acao(lista[i]);
  }
}

paraCadaItem(["A", "B", "C"], function (item) {
  console.log("Item:", item);
});

function processarNumeros(lista, acao) {
  for (let i = 0; i < lista.length; i = i + 1) {
    acao(lista[i], i);
  }
}

processarNumeros([10, 20, 30], function (valor, indice) {
  console.log(indice, valor);
});

const numeros = [1, 2, 3, 4];

const pares = numeros.filter(function (numero) {
  return numero % 2 === 0;
});

console.log(pares);

const numeros = [1, 2, 3];

const quadrados = numeros.map((numero) => numero * numero);
console.log(quadrados);

console.log("Antes");

setTimeout(function () {
  console.log("Depois do tempo");
}, 1000);

console.log("Registro concluído");

campo.addEventListener("input", function () {
  console.log("Valor alterado pelo usuário.");
});
